package pe.edu.utp.tmo.infrastructure.persistence; import java.util.*; import org.springframework.stereotype.Repository; import pe.edu.utp.tmo.dao.TipificacionDAO; import pe.edu.utp.tmo.infrastructure.persistence.repository.TipificacionRepository; import pe.edu.utp.tmo.model.entity.Tipificacion; @Repository public class TipificacionJpaDAO implements TipificacionDAO{ private final TipificacionRepository r; public TipificacionJpaDAO(TipificacionRepository r){this.r=r;} public List<Tipificacion> listarActivas(){return r.findByActivoTrueOrderByNombreAsc();} public Optional<Tipificacion> buscarPorId(Long id){return r.findById(id);} public Tipificacion guardar(Tipificacion t){return r.save(t);} }